function solve(m, n, waitCost) {
    const dist = Array(m).fill().map(() => Array(n).fill(Infinity));
    dist[0][0] = 1; // Starting at (0, 0) with entry cost

    const directions = [[0, 1], [1, 0]]; // Right and Down

    const queue = [{ i: 0, j: 0, time: 1 }];

    while (queue.length > 0) {
        const { i, j, time } = queue.shift();

        // Check if we've reached the destination
        if (i === m - 1 && j === n - 1) {
            return dist[i][j];
        }

        // If current time is odd, we can move right or down
        if (time % 2 === 1) {
            for (const [di, dj] of directions) {
                const ni = i + di;
                const nj = j + dj;

                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    const newTime = time + 1;
                    const newCost = dist[i][j] + (ni + 1) * (nj + 1);
                    if (newCost < dist[ni][nj]) {
                        dist[ni][nj] = newCost;
                        queue.push({ i: ni, j: nj, time: newTime });
                    }
                }
            }
        } else {
            // If current time is even, we must wait
            const newTime = time + 1;
            const newCost = dist[i][j] + waitCost[i][j];
            if (newCost < dist[i][j]) {
                dist[i][j] = newCost;
                queue.push({ i: i, j: j, time: newTime });
            }
        }
    }

    return -1; // If no path found
}
